+		if !allNotFound && lastErr != nil {
+			return "", nil, fmt.Errorf("cluster %s: %w", cluster, lastErr)
+		}
 		return "", nil, fmt.Errorf("workload %s/%s not found in cluster %s", namespace, name, cluster)
